from abc import ABC, abstractmethod


class Plugin(ABC):
    """
    INTERNAL CONTRACT
    All plugins must implement these hooks.
    """

    @abstractmethod
    def is_enabled(self) -> bool:
        pass

    @abstractmethod
    def on_session_start(self, context: dict):
        pass

    @abstractmethod
    def on_session_finish(self, context: dict):
        pass
